// Import required libraries
import { useState, useEffect } from 'react';

// Set constants for authorization endpoint and redirect URI
const AUTHORIZATION_ENDPOINT = '/oauth2/authorize';
const REDIRECT_URI = window.location.origin;
const CLIENT_ID = 'your_client_id';
const SCOPE = 'your_scope';

// Function to generate a random code verifier
function generateCodeVerifier() {
  const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let codeVerifier = '';
  for (let i = 0; i < 96; i++) {
    codeVerifier += alphabet.charAt(Math.floor(Math.random() * alphabet.length));
  }
  return codeVerifier;
}

// Function to generate a random code challenge
function generateCodeChallenge(codeVerifier) {
  const hash = crypto.createHash('sha256');
  hash.update(codeVerifier);
  return hash.digest('base64url');
}

// Function to request authorization code
async function requestAuthorizationCode() {
  try {
    // Generate code verifier and challenge
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = generateCodeChallenge(codeVerifier);

    // Redirect user to authorization endpoint
    const redirectUrl = `${window.location.origin}${AUTHORIZATION_ENDPOINT}?client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&response_type=code&scope=${SCOPE}&state=1234567890&code_challenge=${codeChallenge}&code_challenge_method=S256`;
    window.location.href = redirectUrl;

    // Wait for user to return from authorization endpoint
    const code = new URLSearchParams(window.location.search).get('code');
    if (!code) {
      throw new Error('No authorization code returned');
    }

    // Exchange authorization code for access token
    const response = await fetch('/oauth2/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: `grant_type=authorization_code&code=${code}&redirect_uri=${REDIRECT_URI}`,
    });

    const data = await response.json();
    if (data.error) {
      throw new Error(data.error);
    }

    // Store access token in localStorage
    localStorage.setItem('access_token', data.access_token);

    // Redirect user to protected resource
    window.location.href = '/protected-resource';
  } catch (error) {
    console.error(error);
  }
}

// Function to make API requests using stored access token
async function makeApiRequest() {
  try {
    const response = await fetch('/api/endpoint', {
      method: 'GET',
      headers: { Authorization: `Bearer ${localStorage.getItem('access_token')}` },
    });

    const data = await response.json();
    console.log(data);
  } catch (error) {
    console.error(error);
  }
}

// Call requestAuthorizationCode on page load
requestAuthorizationCode();

// Make API requests when access token is available
if (localStorage.getItem('access_token')) {
  makeApiRequest();
}